3914	\begin{lemma}[The structure-sheaf localization of \(\widetilde{M}\) over \(D(f)\)]
3915	  \label{lem:tilde_toOpen_isLocalizedModule_mathlib}
3916	  \lean{AlgebraicGeometry.tilde.toOpen}
3917	  \mathlibok
3918	  \textit{Provided by Mathlib.}
3919	  For \(M\) an \(R\)-module and \(f \in R\), Mathlib's map
3920	  \(\operatorname{toOpen} : M \to \Gamma(D(f), \widetilde{M})\) exhibits \(\Gamma(D(f), \widetilde{M}) =
3921	  M_f\) as the localization of \(M\) at the powers of \(f\): it carries an
3922	  \(\operatorname{IsLocalizedModule}(\operatorname{powers} f)\) instance. Moreover the global component
3923	  \(\operatorname{toOpen}(M, \top)\) is an isomorphism (Mathlib's
3924	  \(\operatorname{isIso\_toOpen\_top}\)), identifying \(\Gamma(\operatorname{Spec} R, \widetilde{M}) =
3925	  M\).
3926	\end{lemma}
