3928	\begin{lemma}[Transport of a presentation along a colimit-preserving functor]
3929	  \label{lem:presentation_map_mathlib}
3930	  \lean{SheafOfModules.Presentation.map}
3931	  \mathlibok
3932	  \textit{Provided by Mathlib.}
3933	  Let \(F : \operatorname{SheafOfModules} R \to \operatorname{SheafOfModules} S\) be a functor between
3934	  categories of sheaves of modules (possibly over different sites) that preserves colimits and carries
3935	  the unit object to the unit object, \(F(\mathcal{O}_R) \cong \mathcal{O}_S\). Then any presentation
3936	  of a sheaf of modules \(\mathcal{M}\) — a right-exact sequence
3937	  \(\mathcal{O}_R^{(J)} \to \mathcal{O}_R^{(I)} \to \mathcal{M} \to 0\) of generators and relations —
3938	  is carried by \(F\) to a presentation of \(F(\mathcal{M})\).
3939	\end{lemma}
