3941	\begin{lemma}[Transport of a presentation across an isomorphism]
3942	  \label{lem:presentation_ofIsIso_mathlib}
3943	  \lean{SheafOfModules.Presentation.ofIsIso}
3944	  \mathlibok
3945	  \textit{Provided by Mathlib.}
3946	  Let \(\phi : \mathcal{M} \to \mathcal{N}\) be an isomorphism of sheaves of modules. A presentation of
3947	  \(\mathcal{M}\) induces a presentation of \(\mathcal{N}\), by composing its generators and relations
3948	  with \(\phi\).
3949	\end{lemma}
