3951	\begin{lemma}[Site-equivalence transport of sheaves of modules]
3952	  \label{lem:pushforwardPushforwardEquivalence_mathlib}
3953	  \lean{SheafOfModules.pushforwardPushforwardEquivalence}
3954	  \mathlibok
3955	  \textit{Provided by Mathlib.}
3956	  Let \(e : \mathcal{C} \simeq \mathcal{D}\) be an equivalence of sites and let
3957	  \(\mathcal{O}_{\mathcal{C}}\), \(\mathcal{O}_{\mathcal{D}}\) be sheaves of rings related by
3958	  compatible comparison maps along \(e\). Then \(e\) induces an equivalence of categories of sheaves of
3959	  modules \(\operatorname{SheafOfModules} \mathcal{O}_{\mathcal{C}} \simeq
3960	  \operatorname{SheafOfModules} \mathcal{O}_{\mathcal{D}}\), compatible with the underlying
3961	  pushforwards. This is the engine that bridges two pictures of ``restriction to an open''.
3962	\end{lemma}
