4014	[Section-restriction localizes when the counit is an isomorphism (per-piece engine)]
4015	  \label{lem:section_isLocalizedModule_of_isIso_fromTildeGamma}
4016	  \lean{AlgebraicGeometry.section_isLocalizedModule_of_isIso_fromTildeΓ}
4017	  \uses{lem:tilde_section_isLocalizedModule, lem:qcoh_iso_tilde_sections}
4018	  Let \(\mathcal{F}\) be an \(\mathcal{O}_{\operatorname{Spec} R}\)-module for which the
4019	  tilde--\(\Gamma\) counit \(\operatorname{fromTilde\Gamma}\) is an isomorphism, and let \(f \in R\).
4020	  Then the section-restriction map \(\Gamma(\operatorname{Spec} R, \mathcal{F}) \to \Gamma(D(f),
4021	  \mathcal{F})\) is a localization at the powers of \(f\).
4022	\end{lemma}
4023	\begin{proof}
4024	  \uses{lem:tilde_section_isLocalizedModule, lem:qcoh_iso_tilde_sections}
4025	  \leanok
4026	  When \(\operatorname{fromTilde\Gamma}\) is an isomorphism, \(\mathcal{F} \cong \widetilde{M}\) with
4027	  \(M = \Gamma(\operatorname{Spec} R, \mathcal{F})\) (Lemma~\ref{lem:qcoh_iso_tilde_sections}). The
4028	  counit isomorphism, pushed through the forgetful functor, identifies the section-restriction map of
4029	  \(\mathcal{F}\) with that of \(\widetilde{M}\) — compatibly on source and target by naturality. The
4030	  latter is a localization by Lemma~\ref{lem:tilde_section_isLocalizedModule}; conjugating by the
4031	  isomorphism transports the localization property to the section-restriction map of \(\mathcal{F}\).

